// Auto-generated from Roboto-Regular.ttf and Roboto-Bold.ttf (Latin + Cyrillic subset).
// Inlined as base64 because Supabase edge runtime bundles only .ts/.js files;
// binary assets in _shared/ are not deployed alongside the function.

export const ROBOTO_REGULAR_BASE64 = "";

export const ROBOTO_BOLD_BASE64 = "";

export function decodeBase64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}
